  2→ * CounterpartyRepository - CRUD operations for Counterparty model
  3→ *
  4→ * Provides typed methods for Counterparty queries with soft-delete support.
  5→ * All errors propagate to caller for handling at API layer.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type {
 10→  Counterparty,
 11→  Prisma,
 12→} from '@prisma/client';
 13→import { randomUUID } from 'node:crypto';
 14→
 15→/**
 16→ * Counterparty creation input type
 17→ */
 18→export type CounterpartyCreateInput = Omit<Prisma.CounterpartyUncheckedCreateInput, 'id' | 'updatedAt'> & Partial<Pick<Prisma.CounterpartyUncheckedCreateInput, 'id' | 'updatedAt'>>;
 19→
 20→/**
 21→ * Counterparty update input type
 22→ */
 23→export type CounterpartyUpdateInput = Prisma.CounterpartyUncheckedUpdateInput;
 24→
 25→/**
 26→ * Counterparty findMany params type
 27→ */
 28→export type CounterpartyFindManyParams = {
 29→  where?: Prisma.CounterpartyWhereInput;
 30→  orderBy?: Prisma.CounterpartyOrderByWithRelationInput;
 31→  skip?: number;
 32→  take?: number;
 33→  include?: Prisma.CounterpartyInclude;
 34→};
 35→
 36→/**
 37→ * Repository for Counterparty CRUD operations
 38→ */
 39→export class CounterpartyRepository {
 40→  /**
 41→   * Find many counterparties with optional filtering
 42→   * Automatically filters out soft-deleted records
 43→   */
 44→  async findMany(params?: CounterpartyFindManyParams): Promise<Counterparty[]> {
 45→    const { where, ...rest } = params ?? {};
 46→
 47→    return prisma.counterparty.findMany({
 48→      ...rest,
 49→      where: {
 50→        ...where,
 51→        deletedAt: null, // Always exclude soft-deleted
 52→      },
 53→    });
 54→  }
 55→
 56→  /**
 57→   * Find a single counterparty by ID
 58→   * Returns null if not found or soft-deleted
 59→   */
 60→  async findUnique(
 61→    id: string,
 62→    include?: Prisma.CounterpartyInclude
 63→  ): Promise<Counterparty | null> {
 64→    return prisma.counterparty.findFirst({
 65→      where: { id, deletedAt: null },
 66→      include,
 67→    });
 68→  }
 69→
 70→  /**
 71→   * Find a counterparty by INN (dedup check)
 72→   * Returns null if not found or soft-deleted
 73→   */
 74→  async findByInn(inn: string): Promise<Counterparty | null> {
 75→    return prisma.counterparty.findFirst({
 76→      where: { inn, deletedAt: null },
 77→    });
 78→  }
 79→
 80→  /**
 81→   * Find counterparties by type field
 82→   * Returns filtered list excluding soft-deleted
 83→   */
 84→  async findByType(type: string): Promise<Counterparty[]> {
 85→    return prisma.counterparty.findMany({
 86→      where: { type, deletedAt: null },
 87→    });
 88→  }
 89→
 90→  /**
 91→   * Create a new counterparty
 92→   * Generates UUID and updatedAt if not provided (schema requires these fields)
 93→   */
 94→  async create(data: CounterpartyCreateInput): Promise<Counterparty> {
 95→    return prisma.counterparty.create({
 96→      data: {
 97→        ...data,
 98→        id: data.id ?? randomUUID(),
 99→        updatedAt: data.updatedAt ?? new Date(),
100→      },
101→    });
102→  }
103→
104→  /**
105→   * Update an existing counterparty
106→   * Throws Error if counterparty doesn't exist or is soft-deleted
107→   */
108→  async update(
109→    id: string,
110→    data: CounterpartyUpdateInput
111→  ): Promise<Counterparty> {
112→    const existing = await this.findUnique(id);
113→    if (!existing) {
114→      throw new Error(`Counterparty with id ${id} not found`);
115→    }
116→
117→    return prisma.counterparty.update({
118→      where: { id },
119→      data,
120→    });
121→  }
122→
123→  /**
124→   * Soft delete a counterparty by setting deletedAt timestamp
125→   * Does NOT actually delete the record from database
126→   * Throws Error if counterparty doesn't exist or is already soft-deleted
127→   */
128→  async softDelete(id: string): Promise<Counterparty> {
129→    const existing = await this.findUnique(id);
130→    if (!existing) {
131→      throw new Error(`Counterparty with id ${id} not found`);
132→    }
133→
134→    return prisma.counterparty.update({
135→      where: { id },
136→      data: { deletedAt: new Date() },
137→    });
138→  }
139→
140→  /**
141→   * Count counterparties matching criteria (excluding soft-deleted)
142→   */
143→  async count(where?: Prisma.CounterpartyWhereInput): Promise<number> {
144→    return prisma.counterparty.count({
145→      where: {
146→        ...where,
147→        deletedAt: null,
148→      },
149→    });
150→  }
151→
152→  /**
153→   * Check if a counterparty exists by INN (excluding soft-deleted)
154→   */
155→  async existsByInn(inn: string): Promise<boolean> {
156→    const count = await prisma.counterparty.count({
157→      where: { inn, deletedAt: null },
158→    });
159→    return count > 0;
160→  }
161→}
