  1→/**
  2→ * BOMRepository — CRUD operations for BOM and BOMItem models
  3→ *
  4→ * BOM has @unique projectId (1 BOM per project). BOMItem is a child with onDelete: Cascade.
  5→ * Follows CounterpartyRepository pattern: singleton, manual UUID, manual updatedAt.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type { BOM, BOMItem, Prisma } from '@prisma/client';
 10→import { randomUUID } from 'node:crypto';
 11→
 12→/**
 13→ * BOM creation input — projectId is required, items are optional
 14→ */
 15→export type BOMCreateInput = {
 16→  projectId: string;
 17→  sourceFileId?: string;
 18→  items?: (Omit<Prisma.BOMItemUncheckedCreateInput, 'id' | 'bomId' | 'createdAt' | 'updatedAt'> &
 19→    Partial<Pick<Prisma.BOMItemUncheckedCreateInput, 'id' | 'updatedAt'>>)[];
 20→};
 21→
 22→/**
 23→ * BOM update input
 24→ */
 25→export type BOMUpdateInput = Prisma.BOMUncheckedUpdateInput;
 26→
 27→/**
 28→ * BOMItem creation input
 29→ */
 30→export type BOMItemCreateInput = Omit<Prisma.BOMItemUncheckedCreateInput, 'id' | 'createdAt' | 'updatedAt'> &
 31→  Partial<Pick<Prisma.BOMItemUncheckedCreateInput, 'id' | 'updatedAt'>>;
 32→
 33→/**
 34→ * BOMItem update input
 35→ */
 36→export type BOMItemUpdateInput = Prisma.BOMItemUncheckedUpdateInput & {
 37→  updatedAt?: never; // updatedAt is always set by the repository
 38→};
 39→
 40→/**
 41→ * Repository for BOM and BOMItem CRUD operations
 42→ */
 43→export class BOMRepository {
 44→  // ─── BOM CRUD ────────────────────────────────────────────
 45→
 46→  /**
 47→   * Create a BOM with auto-generated id, status='draft', version=1, updatedAt
 48→   * Optionally creates nested BOMItems via the `items` field
 49→   */
 50→  async create(data: BOMCreateInput): Promise<BOM & { items?: BOMItem[] }> {
 51→    const { items, ...bomData } = data;
 52→
 53→    return prisma.bOM.create({
 54→      data: {
 55→        ...bomData,
 56→        id: randomUUID(),
 57→        updatedAt: new Date(),
 58→        status: 'draft',
 59→        version: 1,
 60→        items: items
 61→          ? {
 62→              create: items.map((item, index) => ({
 63→                ...item,
 64→                id: item.id ?? randomUUID(),
 65→                rowNumber: item.rowNumber ?? index + 1,
 66→                updatedAt: item.updatedAt ?? new Date(),
 67→              })),
 68→            }
 69→          : undefined,
 70→      },
 71→      include: { items: true },
 72→    });
 73→  }
 74→
 75→  /**
 76→   * Find a BOM by ID, optionally including its items
 77→   */
 78→  async findById(id: string, includeItems = false): Promise<BOM | null> {
 79→    return prisma.bOM.findUnique({
 80→      where: { id },
 81→      include: { items: includeItems },
 82→    });
 83→  }
 84→
 85→  /**
 86→   * Find a BOM by projectId (1-to-1), optionally including its items
 87→   */
